import React from 'react';
import { Link } from 'react-router-dom';

function Home() {
  return (
    <div className="home-page">
      {/* 1. Hero Section - Image सह */}
      <header className="py-5 text-white" style={{ background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)', minHeight: '85vh', display: 'flex', alignItems: 'center' }}>
        <div className="container py-5 text-center text-lg-start">
          <div className="row align-items-center">
            
            {/* डावी बाजू: मजकूर */}
            <div className="col-lg-6 mb-5 mb-lg-0">
              <h1 className="display-4 fw-bold mb-3 animate__animated animate__fadeInLeft">
                Build Your Next <span className="text-warning">Big Project</span> With Us
              </h1>
              <p className="lead fs-4 mb-4 opacity-75">
                We provide professional web development, creative UI/UX designs, and technical solutions for students and businesses.
              </p>
              <div className="d-grid gap-3 d-sm-flex justify-content-lg-start justify-content-center">
                <Link to="/services" className="btn btn-warning btn-lg px-5 fw-bold shadow">Explore Services</Link>
                <Link to="/register" className="btn btn-outline-light btn-lg px-5 fw-bold">Hire Me Now</Link>
              </div>
            </div>

            {/* उजवी बाजू: इमेज (येथे इमेज टॅग आहे) */}
            <div className="col-lg-6 text-center">
              <div className="image-wrapper shadow-lg rounded-4 p-2 bg-white-50">
                <img 
                  src="https://images.unsplash.com" 
                  alt="Professional Workspace" 
                  className="img-fluid rounded-4 shadow border border-5 border-white"
                  style={{ width: '100%', height: 'auto', display: 'block', minHeight: '350px', objectFit: 'cover' }}
                />
              </div>
            </div>

          </div>
        </div>
      </header>

      {/* 2. Features Section (Clickable Cards) */}
      <section className="py-5 bg-light border-bottom border-top">
        <div className="container py-5 text-center">
          <h2 className="fw-bold mb-5 display-5">Why Work With Me?</h2>
          <div className="row g-4">
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-primary mb-3">⚡</div>
                  <h4 className="fw-bold text-dark">Fast Delivery</h4>
                  <p className="text-muted small">Optimized process to deliver your projects ahead of deadlines.</p>
                </div>
              </Link>
            </div>
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-danger mb-3">📱</div>
                  <h4 className="fw-bold text-dark">Fully Responsive</h4>
                  <p className="text-muted small">Modern websites that work smoothly on all devices, from mobile to desktop.</p>
                </div>
              </Link>
            </div>
            <div className="col-md-4">
              <Link to="/services" className="text-decoration-none">
                <div className="card h-100 border-0 shadow-sm p-4 feature-card">
                  <div className="display-5 text-success mb-3">🔒</div>
                  <h4 className="fw-bold text-dark">Secure Code</h4>
                  <p className="text-muted small">Clean and safe coding practices to ensure your data remains protected.</p>
                </div>
              </Link>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Testimonials Section */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <h2 className="text-center fw-bold mb-5 display-5 text-dark">What My Clients Say</h2>
          <div className="row g-4 text-center">
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"Amazing work! My business website looks so professional now."</p>
                <h6 className="fw-bold mb-0 text-primary">- Rahul Sharma</h6>
              </div>
            </div>
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"Delivered the project 2 days early. Highly recommended!"</p>
                <h6 className="fw-bold mb-0 text-primary">- Sneha Patil</h6>
              </div>
            </div>
            <div className="col-md-4">
              <div className="p-4 border rounded-4 shadow-sm italic bg-light h-100 shadow-hover">
                <p className="text-muted fs-5">"Best developer for React projects. Very helpful and clear."</p>
                <h6 className="fw-bold mb-0 text-primary">- John Doe</h6>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 4. Contact Us & Map Section */}
      <section id="contact" className="py-5 bg-light border-top border-bottom">
        <div className="container py-5">
          <h2 className="text-center fw-bold mb-5 display-5 text-dark">Get In Touch</h2>
          <div className="row g-5 align-items-center">
            <div className="col-lg-6">
              <div className="shadow-lg rounded-4 overflow-hidden border border-4 border-white" style={{ height: '400px' }}>
                <iframe 
                  title="Map"
                  src="https://www.google.com" 
                  width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy">
                </iframe>
              </div>
            </div>
            <div className="col-lg-6">
              <div className="ps-lg-4 text-center text-lg-start">
                <h3 className="fw-bold mb-4 text-primary">Contact Information</h3>
                <div className="mb-4 text-dark fs-5 shadow-sm p-4 bg-white rounded-4 border">
                  <p className="mb-3 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-envelope text-primary me-3"></i> 
                    <strong>Email:</strong> freelancer@example.com
                  </p>
                  <p className="mb-3 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-phone text-success me-3"></i> 
                    <strong>Call:</strong> +91 98765 43210
                  </p>
                  <p className="mb-0 d-flex align-items-center justify-content-center justify-content-lg-start">
                    <i className="fas fa-map-marker-alt text-danger me-3"></i> 
                    <strong>Location:</strong> Nashik, Maharashtra, India
                  </p>
                </div>
                <Link to="/register" className="btn btn-primary btn-lg w-100 fw-bold shadow-sm">
                   Send Project Request
                </Link>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 5. Footer Style CTA */}
      <footer className="py-5 text-center container my-5 bg-dark text-white rounded-5 p-5 shadow-lg">
        <h2 className="fw-bold mb-3">Ready to start your next project?</h2>
        <p className="lead mb-4 opacity-75">Let's collaborate and bring your ideas to life with professional expertise.</p>
        <Link to="/register" className="btn btn-primary btn-lg px-5 fw-bold shadow">Hire Me Now</Link>
      </footer>

      {/* CSS Styles */}
      <style>{`
        .feature-card { transition: 0.3s; cursor: pointer; }
        .feature-card:hover { transform: translateY(-10px); box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; }
        .shadow-hover:hover { box-shadow: 0 10px 20px rgba(0,0,0,0.1) !important; transition: 0.3s; }
      `}</style>
    </div>
  );
}

